Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it hosts your app in-memory and gives you an `HttpClient` that talks to it without opening a real port.

### Setup

```bash
dotnet add tests/MyMcp.Tests package Microsoft.AspNetCore.Mvc.Testing
dotnet add tests/MyMcp.Tests package xunit
```

### Example test

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        // Initialize first (required by MCP)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/list",
            @params = new { }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    private async Task InitializeSession()
    {
        var init = new
        {
            jsonrpc = "2.0", id = 0, method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test", version = "1.0" }
            }
        };
        await _client.PostAsJsonAsync("/mcp", init);
    }
}
```

### Key points

| Concept | Detail |
|---|---|
| **No real port** | `WebApplicationFactory` uses an in-memory `TestServer` — no TCP listener |
| **Full pipeline** | Middleware, DI, routing, auth — everything runs as in production |
| **Session state** | If your server uses MCP sessions (`Mcp-Session-Id`), capture the header from the `initialize` response and attach it to subsequent requests |
| **SSE transport** | For Streamable HTTP with SSE, read the response stream with `ReadAsStreamAsync()` and parse `text/event-stream` lines |
| **Service overrides** | Use `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in test doubles (e.g., mock databases) |

### Handling SSE responses

```csharp
[Fact]
public async Task ToolCall_WithSseStream()
{
    await InitializeSession();

    var request = new
    {
        jsonrpc = "2.0", id = 3, method = "tools/call",
        @params = new { name = "my-tool", arguments = new { input = "hello" } }
    };

    var response = await _client.PostAsJsonAsync("/mcp", request);

    if (response.Content.Headers.ContentType?.MediaType == "text/event-stream")
    {
        using var stream = await response.Content.ReadAsStreamAsync();
        using var reader = new StreamReader(stream);
        while (await reader.ReadLineAsync() is { } line)
        {
            if (line.StartsWith("data: "))
            {
                var json = JsonDocument.Parse(line[6..]);
                // assert on streamed JSON-RPC messages
            }
        }
    }
}
```

This gives you full MCP protocol coverage — initialize, tools/list, tools/call, notifications — all running in-process with zero network overhead.
